// Solution: Use a regular expression to match the route path and parameter pattern
function validateRoute(route, param) { let regex = /^[/][a-zA-Z0-9]+(:[a-zA-Z0-9]+)?$/; if (regex.test(route) && param.match(/^[a-zA-Z0-9]+$/)) { return true; } else { return false; } }

function main(route, param) { let result = validateRoute(route, param); console.log(result); }

// Test cases
main('GET /users/123', '123');
main('GET /users/name', 'name');

