class Solution: 
  def validateRoute(self, route, param): 
    regex = r'^/[a-zA-Z0-9]+(:[a-zA-Z0-9]+)?$' 
    if regex.match(route) and param.isalnum(): 
      return True 
    else: 
      return False

# Test cases
